#!/bin/bash\n\n# Performance Test Runner for Multi-Engine AI Routing\n# Runs baseline, stress, and spike tests with Artillery\n\nset -e\n\necho \"========================================\"\necho \"Performance Test Suite - Engine Resolution\"\necho \"========================================\"\necho \"\"\n\n# Colors for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m' # No Color\n\n# Check if Artillery is installed\nif ! command -v artillery &> /dev/null; then\n    echo -e \"${RED}Artillery not found. Install with: npm install -g artillery${NC}\"\n    exit 1\nfi\n\n# Check if server is running\necho \"Checking if server is running on http://localhost:3000...\"\nif ! curl -s http://localhost:3000 > /dev/null; then\n    echo -e \"${RED}Server not running on http://localhost:3000${NC}\"\n    echo \"Please start the server with: npm run dev\"\n    exit 1\nfi\necho -e \"${GREEN}âś“ Server is running${NC}\"\necho \"\"\n\n# Create results directory\nRESULTS_DIR=\"./load-tests/results\"\nmkdir -p \"$RESULTS_DIR\"\nTIMESTAMP=$(date +%Y%m%d_%H%M%S)\n\necho \"Running performance tests...\"\necho \"\"\n\n# Test 1: Baseline\necho -e \"${YELLOW}[1/3] Running Baseline Test...${NC}\"\necho \"      Single request per second for 30 seconds\"\nartillery run load-tests/baseline.yml -o \"$RESULTS_DIR/baseline_${TIMESTAMP}.json\" 2>&1 | tail -20\necho -e \"${GREEN}âś“ Baseline test completed${NC}\"\necho \"\"\n\n# Test 2: Stress\necho -e \"${YELLOW}[2/3] Running Stress Test...${NC}\"\necho \"      Ramp-up: 10 to 100 RPS (60s) â†’ Sustained: 100 RPS (5m) â†’ Ramp-down: 100 to 0 RPS (60s)\"\nartillery run load-tests/stress.yml -o \"$RESULTS_DIR/stress_${TIMESTAMP}.json\" 2>&1 | tail -20\necho -e \"${GREEN}âś“ Stress test completed${NC}\"\necho \"\"\n\n# Test 3: Spike\necho -e \"${YELLOW}[3/3] Running Spike Test...${NC}\"\necho \"      Baseline (10 RPS) â†’ Spike (150 RPS) â†’ Recovery â†’ Baseline\"\nartillery run load-tests/spike.yml -o \"$RESULTS_DIR/spike_${TIMESTAMP}.json\" 2>&1 | tail -20\necho -e \"${GREEN}âś“ Spike test completed${NC}\"\necho \"\"\n\necho \"========================================\"\necho -e \"${GREEN}All tests completed!${NC}\"\necho \"========================================\"\necho \"\"\necho \"Results saved to: $RESULTS_DIR/\"\necho \"\"\necho \"To generate HTML reports:\"\necho \"  artillery report $RESULTS_DIR/baseline_${TIMESTAMP}.json\"\necho \"  artillery report $RESULTS_DIR/stress_${TIMESTAMP}.json\"\necho \"  artillery report $RESULTS_DIR/spike_${TIMESTAMP}.json\"\necho \"\"\n
